INSERT INTO t_p48876731_clinic_ortho_website.doctors (name, specialty, experience, description, img, img_position, img_height, img_margin_top, sort_order) VALUES
('Буланбаев Бекболот Ардинатович', 'Врач травматолог-ортопед', 'Травматология · Ортопедия · УЗИ суставов', 'Опытный врач травматолог‑ортопед в Новосибирске, специализирующийся на диагностике и лечении заболеваний опорно‑двигательного аппарата: артроза, артрита, бурсита, синовита, тендинита и энтезита. Сочетает современные методы лечения — PRP‑терапию, медикаментозные блокады, введение гиалуроновой кислоты — с точной инструментальной диагностикой (УЗИ суставов, рентген, МРТ) и индивидуальным подходом к каждому пациенту. Ведёт пациента полностью: от первичной консультации до контроля результатов лечения.', 'https://cdn.poehali.dev/projects/6e339ebb-3990-4eb0-b0e9-b0325ebc1901/bucket/1017135a-54d3-4d0d-9a11-65fd55dbb932.JPG', 'center 10%', '', '', 1),
('Дуйшеналиев Канатбек Дуйшеналиевич', 'Врач травматолог-ортопед', 'Травматология · Ортопедия · PRP-терапия · SVF-терапия', 'Врач травматолог-ортопед в Новосибирске. Диагностика и лечение травм и заболеваний опорно-двигательного аппарата. Проводит PRP-терапию и SVF-терапию, внутрисуставные и паравертебральные блокады, пункции суставов с введением лекарственных препаратов. Консервативное лечение: репозиция переломов, вправление вывихов, иммобилизация.', 'https://cdn.poehali.dev/projects/6e339ebb-3990-4eb0-b0e9-b0325ebc1901/bucket/70271e2d-4950-4f42-9bb0-74b0709c3806.JPG', 'center top', 'calc(26rem + 3px)', '-1cm', 2);
INSERT INTO t_p48876731_clinic_ortho_website.services (slug, icon, title, short_desc, full_desc, items, color, sort_order) VALUES
('orthopedics', 'Bone', 'Ортопедия', 'Лечение заболеваний суставов, позвоночника и деформаций опорно-двигательного аппарата', 'Консервативное лечение артроза, артрита, деформаций стопы, остеохондроза и заболеваний позвоночника. Врач подбирает индивидуальную программу терапии и, при необходимости, расписывает курс реабилитации после лечения.', '["Лечение артроза и артрита суставов","Лечение остеохондроза и межпозвоночных грыж","Коррекция деформаций стопы (вальгус, плоскостопие)","Лечение сколиоза и нарушений осанки","Подбор ортопедических стелек и ортезов"]', 'bg-blue-50 text-blue-600', 1),
('traumatology', 'Bandage', 'Травматология', 'Лечение переломов, вывихов, разрывов связок и травм опорно-двигательного аппарата', 'Комплексная помощь при острых травмах и последствиях застарелых повреждений. Применяем консервативные методы фиксации и лечения. После завершения основного курса врач составляет индивидуальную программу реабилитации для полного восстановления функций.', '["Лечение переломов и трещин костей","Вправление и лечение вывихов","Лечение разрывов связок и сухожилий","Лечение повреждений мениска","Лечение последствий спортивных травм"]', 'bg-rose-50 text-rose-600', 2),
('blockades', 'ShieldPlus', 'Блокады', 'Лечебные блокады для быстрого снятия боли при патологиях суставов и позвоночника', 'Паравертебральные и периартикулярные блокады — эффективный метод быстрого купирования болевого синдрома. Процедура проводится опытным врачом-ортопедом в условиях клиники, снимает воспаление и восстанавливает подвижность за один сеанс.', '["Блокады при болях в шейном отделе позвоночника","Блокады при болях в поясничном отделе позвоночника","Периартикулярные блокады плечевого сустава","Блокады при эпикондилите (теннисный локоть)","Блокады триггерных точек при миофасциальном синдроме"]', 'bg-indigo-50 text-indigo-600', 3),
('injections', 'Syringe', 'Инъекции', 'Внутрисуставные инъекции, PRP-терапия и гиалуроновая кислота', 'Современные инъекционные методы лечения суставов без операции. Инъекции гиалуроновой кислоты восстанавливают суставную жидкость, PRP-терапия запускает собственные механизмы регенерации тканей — результат сохраняется до 12–18 месяцев.', '["Инъекции гиалуроновой кислоты в суставы","PRP-терапия (плазмолифтинг) суставов","SVF-терапия стромально-васкулярной фракцией","Внутрисуставное введение кортикостероидов","Пролотерапия при нестабильности связок"]', 'bg-green-50 text-green-600', 4),
('analyses', 'FlaskConical', 'Анализы', 'Лабораторные анализы крови, мочи и синовиальной жидкости', 'Клиника проводит забор биоматериала и направляет образцы в аккредитованную лабораторию. Результаты анализов помогают врачу поставить точный диагноз, оценить активность воспаления и подобрать оптимальное лечение.', '["Общий и биохимический анализ крови","Маркёры воспаления (СРБ, ревматоидный фактор)","Анализ на мочевую кислоту (диагностика подагры)","Гормональные и иммунологические исследования","Исследование синовиальной жидкости сустава"]', 'bg-amber-50 text-amber-600', 5),
('infusions', 'Droplets', 'Внутривенные инфузии', 'Капельницы с хондропротекторами, противовоспалительными и обезболивающими препаратами', 'Внутривенное введение лекарственных препаратов обеспечивает быстрое и точное действие — без потерь при прохождении через желудочно-кишечный тракт. Курс капельниц назначается врачом при выраженном болевом синдроме, обострении артроза или системных воспалительных заболеваниях.', '["Капельницы с хондропротекторами (хондроитин, глюкозамин)","Внутривенная противовоспалительная терапия","Инфузионная обезболивающая терапия","Капельницы с препаратами для улучшения кровообращения","Витаминно-минеральные инфузии для восстановления суставов"]', 'bg-cyan-50 text-cyan-600', 6);
